document.addEventListener("DOMContentLoaded",()=>{gsap.registerPlugin(ScrollTrigger);const e=document.getElementById("hero-video");if(!e)return;const t=()=>{let t=gsap.timeline({defaults:{ease:"none"},scrollTrigger:{trigger:"#scroll-track",start:"top top",end:"bottom bottom",scrub:.5}}),o=e.duration||10,r={time:0};t.to(r,{time:o,onUpdate:()=>{e.readyState>=2&&(e.currentTime=r.time)}},0),t.fromTo("#parallax-float-1",{y:50,rotation:0},{y:-100,rotation:5},0),t.fromTo("#parallax-float-2",{y:100,rotation:0},{y:-60,rotation:-4},0),t.fromTo(".video-element",{scale:1.05},{scale:1.15},0)};e.readyState>=1?t():e.addEventListener("loadedmetadata",t);document.querySelectorAll(".gsap-reveal").forEach(e=>{const t=parseFloat(e.getAttribute("data-delay"))||0;gsap.fromTo(e,{opacity:0,y:50,scale:.95,filter:"blur(12px)"},{opacity:1,y:0,scale:1,filter:"blur(0px)",duration:1.4,delay:t,ease:"power3.out",scrollTrigger:{trigger:e,start:"top 85%"}})}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){const t=this.getAttribute("href"),o=document.querySelector(t);o&&(e.preventDefault(),o.scrollIntoView({behavior:"smooth",block:"start"}))})}),document.querySelectorAll(".feature-card, .flashlight-card, .fintech-card").forEach(e=>{e.addEventListener("mousemove",t=>{const o=e.getBoundingClientRect(),r=t.clientX-o.left,a=t.clientY-o.top;e.style.setProperty("--mouse-x",`${r}px`),e.style.setProperty("--mouse-y",`${a}px`)})});document.querySelectorAll(".parallax-item").forEach(e=>{const t=parseFloat(e.getAttribute("data-speed"))||0;gsap.to(e,{y:(e,o)=>-ScrollTrigger.maxScroll(window)*t,ease:"none",scrollTrigger:{trigger:e.closest("section"),start:"top bottom",end:"bottom top",scrub:.5,invalidateOnRefresh:!0}})})});